<?php
declare(strict_types=1);
$payload = trim((string)($_GET['code'] ?? ''));
$title = trim((string)($_GET['title'] ?? 'Signed Quest Code')) ?: 'Signed Quest Code';
function lqsp_h(string $value): string { return htmlspecialchars($value, ENT_QUOTES, 'UTF-8'); }
$qrUrl = $payload !== '' ? 'https://api.qrserver.com/v1/create-qr-code/?size=360x360&data=' . rawurlencode($payload) : '';
?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?= lqsp_h($title) ?></title><style>body{margin:0;background:#f8fafc;color:#0f172a;font-family:Arial,sans-serif}.sheet{width:min(760px,92%);margin:0 auto;padding:36px 0;text-align:center}.card{background:#fff;border:1px solid #cbd5e1;border-radius:24px;padding:28px;box-shadow:0 18px 60px rgba(15,23,42,.12)}img{width:360px;max-width:100%;height:auto}.code{margin-top:20px;word-break:break-all;font-family:ui-monospace,Menlo,Consolas,monospace;font-size:11px;background:#f1f5f9;padding:12px;border-radius:12px;text-align:left}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:38px;padding:0 14px;border-radius:12px;background:#0f172a;color:#fff;text-decoration:none;font-weight:800;margin:10px}@media print{.actions{display:none}.card{box-shadow:none}}</style></head><body><main class="sheet"><section class="card"><h1><?= lqsp_h($title) ?></h1><?php if($payload): ?><img src="<?= lqsp_h($qrUrl) ?>" alt="Signed QR code"><p>Scan this QR code to complete a protected quest.</p><div class="code"><?= lqsp_h($payload) ?></div><?php else: ?><p>No signed code provided. Generate a code from the admin signed-code tool, then open this page with a code query parameter.</p><?php endif; ?><div class="actions"><a class="btn" href="javascript:window.print()">Print</a><a class="btn" href="admin-signed-codes.php">Back to generator</a></div></section></main></body></html>
